/// <reference path="../../index.d.ts" />
import type NamedTraceConfiguration from "@arcgis/core/networks/support/NamedTraceConfiguration.js";
import type { PublicLitElement as LitElement } from "@arcgis/lumina";
import type { T9nMeta } from "@arcgis/lumina/controllers";

/**
 * This is a sub-component used by the **ArcgisUtilityNetworkTraceAnalysis** component.
 *
 * This sub-component takes a utility network and named trace configuration as input.
 * The sub-component displays information from the trace configuration relevant to subnetworks:
 * Domain network name, tier name, and target tier name.
 *
 * @since 4.34
 * @internal
 */
export abstract class ArcgisUtilityNetworkSubnetworkInfo extends LitElement {
  /** @internal */
  protected _messages: { headings: {
      domainNetwork: string;
      targetTier: string;
      tier: string;
  }; } & T9nMeta<{ headings: {
      domainNetwork: string;
      targetTier: string;
      tier: string;
  }; }>;
  /** @required */
  accessor namedTraceConfig: NamedTraceConfiguration | undefined;
}